  -- Artists (parsed from set artist_name strings)
  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('A Guy Called Gerald presents Black Secret Technology', 'a guy called gerald presents black secret technology', false, 'Few artists can claim a legacy as deep and far-reaching as A Guy Called Gerald. Emerging out of Manchester in the late 1980s, he helped shape electronic music as we know it, leaving an indelible mark on acid house, jungle, and beyond. From the era-defining Voodoo Ray (1988) to the frenetic energy of 28 Gun Bad Boy (1993), his work consistently broke new ground. His fourth album, Black Secret Technology (1995), marked a further leap forward: an immersive, future-facing record that inspired fellow musicians – including David Bowie – and permanently altered the course of drum & bass, breakbeat, and other percussive styles. More than three decades on, the album remains a singular statement – visionary then, and undiminished now. Don’t miss the chance to witness a true classic come alive.', 'https://dekmantelfestival.com/artists/a-guy-called-gerald-presents-black-secret-technology-live')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

