  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Alex Wilcox', 'alex wilcox', false, 'Originally from Dallas, Texas and now based in Berlin via Austin, LA and Detroit, Alex Wilcox channels a wide range of influences into his electronic productions. Delivering sonic whirlwinds at turbo-speed BPMs, infused with heavy doses of pop, funk, electroclash, hardcore and punk, he pushes techno into strange and unexpected territory. His boundary-stretching practice centres on vocal experimentation, whether twisting his own voice or collaborating with artists such as CATNAPP and Chippy Nonstop. Following standout EPs on labels including Mama Told Ya and trip, Alex Wilcox released his debut album on BPitch last year.', 'https://dekmantelfestival.com/artists/alex-wilcox-live')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('AMORAL', 'amoral', false, 'Amsterdam’s AMORAL has quickly made her way to some of techno’s most loved spaces, from New York’s BASEMENT to regular appearances at Berghain. Back in Amsterdam, she runs the clubbers’ favourite event series Eerste Communie, where she is also a resident. In true Eerste Communie style, AMORAL’s sound is endlessly rolling and vibrant, with a euphoric undertone. After showcasing her unique take on techno at Dekmantel Ten and in our UFO last year, we’re gearing up for another trip through her carefully crafted wormhole.', 'https://dekmantelfestival.com/artists/amoral-2')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Aurora Halal', 'aurora halal', false, 'If you’ve set foot on Dekmantel ground before, chances are you’ve felt it being shaken by Aurora Halal. This Brooklyn‑based favourite runs the respected Mutual Dreaming party series and the like-minded festival Sustain-Release. As a producer and DJ, with regular appearances at Berghain and, previously, at De School, Aurora Halal has developed a shadowy, psychedelic style that melds techno subgenres together through experimental textures and dreamy, detailed soundscapes. She’s the kind of artist whose sonic journeys equally cater to body and mind, leaving you both breathless and wonderfully fulfilled.', 'https://dekmantelfestival.com/artists/aurora-halal')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Aya', 'aya', false, 'Aya’s work explores the transformative impact of sound, memory and experience on the physical body. Moving between fractured club music, experimental electronics and high-pressure rhythms, both her productions and performances channel raw emotion – “I like crying in the booth” – and release. Known for raw sets that push both structure and sensation, aya draws heavily on the restless energy of the think break (aka the second most sampled drum break in music history after the Amen) while blurring the boundaries between the dancefloor and more abstract listening spaces. Since emerging under her own name, she has released on labels including Tri Angle Records, Astral Plane and Wisdom Teeth. This summer marks the artist’s Dekmantel debut.', 'https://dekmantelfestival.com/artists/aya-live')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Batu', 'batu', false, 'We just can’t seem to get enough of Batu – and there’s a reason he keeps coming back to Dekmantel. A near-permanent fixture at the festival over the years, the Timedance founder has built a reputation for sets that never repeat themselves, constantly reworking his sound while staying tightly locked to the dancefloor. Rooted in UK bass but restless by nature, Batu’s approach favours intricate polyrhythms and elastic low-end pressure that feels perpetually in motion. From his 2022 debut album Opal to a steady run of forward-leaning releases on Timedance and beyond, his music resists fixed form, thriving instead on tension, detail and surprise. Familiar, yes – but never predictable.', 'https://dekmantelfestival.com/artists/batu-2')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Ben UFO', 'ben ufo', false, 'One of the architects of contemporary electronic sound, Ben UFO is a London-based DJ celebrated for his restless, wide-angle approach to the dancefloor. His swift, finely judged mixing journeys from one side of the UK club music spectrum to the other, gliding across garage, grime, and dubstep, and bass, often within the same breath. As co-founder of Hessle Audio, the imprint he has run alongside Pearson Sound and Pangaea since 2007, his curatorial vision has left a lasting imprint through landmark releases by artists such as James Blake, Blawan, and the Hessle trio themselves. A formative presence on Rinse FM – the radio platform synonymous with modern British bass culture – Ben UFO honed his craft through deep listening, patience, and sound-system intuition.', 'https://dekmantelfestival.com/artists/ben-ufo')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective)
  VALUES ('Call Super', 'call super', false)
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Objekt', 'objekt', false, 'A true thing of beauty, Objekt’s DJ sets demand to be experienced in their full splendour – from start to finish; from tears to ecstasy and back again. The Berlin-based DJ and producer has built a reputation for mixes that twist and turn through the outer edges of dance music, pulling together everything from razor-edged techno and industrial rhythms to IDM oddities, ambient experiments, and plenty of bass-heavy wobble. What holds it all together is a meticulous sense of structure: sounds are placed with precision, tension slowly accumulates, and moments of release arrive exactly when they should. Since his initial breakthrough, Objekt has continued to refine this restless approach. In recent years, he launched the label Kapsela, a platform for his evolving sonic experiments and for kindred artists such as PVA and gyrofield, while continuing to reshape expectations of what a club set can be.', 'https://dekmantelfestival.com/artists/objekt')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective)
  VALUES ('Pariah', 'pariah', false)
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Benny Rodrigues', 'benny rodrigues', false, 'One of the greatest disc jockeys to ever come from Dutch soil, please welcome Benny Rodrigues to Dekmantel ’26. Last year, Rotterdam’s one and only joined us under his ROD alias – teaming up with Sterac to flood UFO 1 with unrelenting techno. This summer, he returns under his original moniker, which means you can expect a higher dose of groove‑laden, high-adrenaline (tech‑)house, with irresistible influences from the realms of Detroit, minimal, and acid. Rodrigues was previously named The Netherlands’ most influential DJ – and there’s good reason for it. Once you’ve experienced him in action, the party never stops.', 'https://dekmantelfestival.com/artists/benny-rodrigues')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Beste Hira', 'beste hira', false, 'Classically trained musician Beste Hira brings a deep grasp of craft to the decks. After reaching conservatory level in cello and piano, she pivoted to pursue her calling as a DJ, carrying years of study directly into the club. Behind the turntables, her extensive musical grounding is palpable: she meticulously experiments with sound, guided by an intuition that allows her to push boldly beyond familiar terrain. Originally from Istanbul and now based in Amsterdam, Hira channels the hypnotic, fast-paced, and darker edges of techno with precision and intent. The result is a full-bodied, immersive journey – intense, considered, and vividly alive to the moment.', 'https://dekmantelfestival.com/artists/beste-hira')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Bitter Babe', 'bitter babe', false, 'Artist Profiles - Dekmantel Festival NEWBitter Babe is part of a new generation of artists reshaping the electronic sound of the Latin American diaspora. Originally from Bogotá, emerging through Miami’s thriving underground, and now based in Paris, the genre-defying DJ and producer delivers an energetic blend of bold influences. Moving fluidly between raptor house, breakbeat, techno, guaracha, and infectious dembow, her sound is rooted in bass-heavy grooves and percussive rhythms built for the dancefloor.', 'https://dekmantelfestival.com/artists/bitter-babe')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
