    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Cari Lekebusch presents Vector', 'cari lekebusch presents vector', false, 'Even if the name Vector doesn’t immediately ring a bell, Cari Lekebusch likely does. Between 1992 and 1997, the Swedish producer released a large number of tracks under this specific alias – just one of his many, many monikers – on Glenn Wilson’s Planet Rhythm Records. From its cold, frantic yet controlled sound to its track titles (case in point: ‘The Matrix,’ ‘Mental Hunter,’ ‘Stockholm to Berlin and Back’) and graphic aesthetic, the Vector collection is peak ’90s techno. At Dekmantel Festival ’26, Cari Lekebusch will take you on a one-off live trip down Vector’s deep, dark memory lane.', 'https://dekmantelfestival.com/artists/cari-lekebush-presents-vector-live')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('CCL', 'ccl', false, 'A master of opaque moods and rhythmic chicanes, CCL triggers combustive shifts through wiggle-steppers, trip-no, dub-core, cowgirl breaks, trip funk and beyond. While many DJs traverse genres, few do so with such elasticity; CCL glides between tempos and textures — from speedy 160 BPM to the hot, slung momentum of 100 — with transitions that feel both mischievous and breathlessly precise. Drawing on roots in Bristol and North American DIY scenes — as a talent buyer, festival organiser and obsessive record collector — they approach the dancefloor as a space of fluidity and liminality, opening wormholes between eras, regions and styles. On the RADAR stage, CCL appears at their most unbound; for a more focused approach, catch their Invisible Cities showcase, a mix inspired by their forthcoming project on Dekmantel Records.', 'https://dekmantelfestival.com/artists/ccl-2')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('CCL presents Invisible Cities', 'ccl presents invisible cities', false, 'CCL is a Berlin-based DJ, producer, and curator whose practice spans club culture, radio, and long-form conceptual projects. Guided by what they call “the liquefaction of rhythmic and melodic matter,” their mixing is nothing short of magic, gliding between sounds and tempos to expose hidden connections and productive frictions to spellbinding effect. For Dekmantel Festival 2026, CCL presents a set inspired by Invisible Cities, Italo Calvino’s 1972 novel, which imagines surreal, shifting urban landscapes shaped by desire. First conceived as an NTS Radio show, Invisible Cities also names CCL’s forthcoming project on Dekmantel Records. This special set weaves speculative atmospheres and unexpected rhythms — moving from deep house and techno through electro, dub, ambient, and beatless interludes — unstable, immersive, and always hinting at something just out of view.', 'https://dekmantelfestival.com/artists/ccl-presents-invisible-cities')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Channel One', 'channel one', false, 'Bass for breakfast? Yes, please! Last with us in ’22, we’re thrilled to have Channel One back in the forest – this time for a special morning session as part of our At Dawn programme. One of the UK’s most beloved and respected reggae sound systems, Channel One is comprised of DJ Mikey Dread, MC Macky Banton and MC Ras Sherby. Formed in the late seventies, they first played London’s Notting Hill Carnival in 1983 – and haven’t skipped a year since. Prepare for a big bath of heavyweight sounds and an early dip in the deep end of dub.

Please note that this act is part of Dekmantel at Dawn, which is exclusively accessible to weekend ticket holders.', 'https://dekmantelfestival.com/artists/channel-one')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Cheyanne Hudson', 'cheyanne hudson', false, 'Cheyanne Hudson is an undeniably bright new star on the club firmament. Born and raised in the Netherlands, the British Jamaican/Hong Kong DJ is a resident on Brussels’ Kiosk Radio whose sound is just as fluently diverse as her background. Sound system culture, in particular, is where Cheyanne draws her inspiration, with her sets thriving on snappy amen breaks, low-end frequencies and dubby chants. And while her energy in the booth is light and breezy – yes, go see and feel it for yourself – the deep, dark and gloomy sounds she dabbles in are strong enough to seize both mind and body.', 'https://dekmantelfestival.com/artists/cheyanne-hudson')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Christian AB', 'christian ab', false, 'Over the past decade, Christian AB – who makes his Dekmantel debut this summer – has built a distinctive voice in electronic music through deep, vinyl-based DJing and production. His sets move fluidly between house, techno, breaks and electro – blending his bottomless musical knowledge with an instinctive, razor-sharp understanding of the eb and flow of the dancefloor. As a producer, the Berlin-based artist has released work on imprints such as Faith Beat and Timeless, translating his vision into records that equally stand out for their clarity and depth. We’re thrilled to have him play the forest for the very first time.', 'https://dekmantelfestival.com/artists/christian-ab')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Colin Benders', 'colin benders', false, 'It’s difficult not to get blown away by Colin Benders. A master of modular techno, the Dutch artist – who first made a name for himself under the Kyteman moniker – takes live improvisation to a whole new level. When Benders takes to the booth, there’s always a sense of duality. On the one hand, his performances are raw, tense, instinctive and visceral. At the same time, his live hardware sounds hypnotise and mesmerise, reaching as far as the meditative and transcendental. For Dekmantel ’25, Colin Benders will perform a special At Dawn show.

Please note that this act is part of Dekmantel at Dawn, which is exclusively accessible to weekend ticket holders.', 'https://dekmantelfestival.com/artists/colin-benders')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('DARKSIDE', 'darkside', false, 'If we were to make a list of electronic albums that defined the ’10s, DARKSIDE’s ‘Psychic’ would sit very close to the top. Released in 2013, that spellbinding first outing by producer/composer/multi-instrumentalist Nicolas Jaar and guitarist/sound designer Dave Harrington immediately confirmed what we already knew: these are two of the greatest electronic musicians in the game, laying out an entirely new experimental crossroads between psychedelic rock, techno, minimal and jazz-dub. Following a long hiatus, ‘Spiral’ (2021) finally brought new DARKSIDE material into the world, followed by a brilliant live album in 2023. By then, the duo had become a trio, with Tlacael Esparza joining on drums. Renowned for their lush long-form live shows and deep, slow-burning builds, we’re very proud to bring Darkside to Dekmantel Festival for the first time.', 'https://dekmantelfestival.com/artists/darkside')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

