  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Dax J', 'dax j', false, 'Stripping techno down to its rawest elements – rhythm, repetition, and release – Dax J’s intense, industrial-leaning sound is unmistakably his own. Headlining institutions such as Berghain and Bassiani, the London-born artist rose from the underground to global prominence, earning accolades from Resident Advisor, DJ Mag, and Groove Magazine along the way. Across records released on his own Monnom Black imprint – including the celebrated albums Shades of Black and Offending Public Morality – he has consistently pushed the form forward. In his live shows, relentless productions driven by distorted percussion blur the line between performance and pressure test, locking dancers into a hypnotic, high-tempo momentum. Fierce, focused, and utterly face-melting, this live set marks Dax J’s first in the Netherlands for eight years. His performance is also a brand-new live show – experienced here at Dekmantel for the very first time.', 'https://dekmantelfestival.com/artists/dax-j-live')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Death In Vegas', 'death in vegas', false, 'Death In Vegas is the influential, long-running project of Richard Fearless, a British musician who has spent the last three decades moving between rock, psychedelia and techno with little concern for categorisation. While the group’s early releases sat closer to big beat and band dynamics, later work became increasingly minimal, hypnotic and club-informed (Fearless himself started out as a resident DJ at London’s Job Club in the ’90s). Across their prolific output, including multiple LPs, atmosphere-building and a brooding sense of repetition are ever present. In addition, a mind-blowing roster of collaborators over the years includes Bobby Gillespie, Iggy Pop, The Jesus and Mary Chain’s Jim Reid and Mazzy Star’s Hope Sandoval. This summer, Death In Vegas will perform as part of our Thursday live program.', 'https://dekmantelfestival.com/artists/death-in-vegas')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Dekmantel Soundsystem', 'dekmantel soundsystem', false, 'We might be biased, but Dekmantel Soundsystem is Amsterdam’s groove engine. Two selectors, one seamless conversation between eras, genres, and energy. Now powered by Casper Tielrooij and Interstellar Funk, the duo embodies the city’s musical spirit: history-minded but forward-thinking and impossible to pin down. Their sets are adventures built on tension and texture where deep house can melt into dubby techno or EBM grit meets cosmic funk. No gimmicks, just pure dialogue between two storytellers who balance risk with reward. For this set, they will be joined by a selection of friends for even more unpredictable fun.', 'https://dekmantelfestival.com/artists/dekmantel-soundsystem')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Dimi Angélis', 'dimi angélis', false, 'If you have any connection to Amsterdam’s electronic scene, the name Dimi Angélis – aka Dimitri van Duynhoven – is sure to ring a bell. Ever since finding his footing at illegal raves and warehouse parties in the ’90s, the Dutch artist has fulfilled many roles: from organiser and promoter to globally recognised DJ, producer and label head. The common thread running through all of these functions is the artist’s love for hammering techno that always tells an uncompromising story. Strongly opposed to a phenomenon he calls “easy pleasing,” a Dimi Angélis set always contains a sense of sonic familiarity, only to then throw you off while wrapping you around his finger. If you still need an introduction to the Dimi direction, the solo label ANGLS – on which he’s been releasing techno productions in all possible shades for over a decade – is the perfect place to start.', 'https://dekmantelfestival.com/artists/dim-angélis')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective)
  VALUES ('Dino Sabatini', 'dino sabatini', false)
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective)
  VALUES ('Luigi Tozzi', 'luigi tozzi', false)
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('DirtyLang', 'dirtylang', false, 'Few things excite us more than seeing a new crop of DJs take over the Dekmantel decks. This year, two of those emerging talents are Dirtydms and Helmond Lang – the Rotterdam artists collectively known as DirtyLang and the opening DJs of our bass haven, The Nest. Dirtydms (Alice Vink) is a DJ and designer whose inspiration is rooted in nature and human relationships, with a sound that ranges from tranquil ambient to gritty grime, IDM and footwork. Helmond Lang (Jip Boxstart) is an all-round creative spirit whose adventurous selections – regularly broadcast on Operator Radio – revolve around deep, resonant bass. What these DJs have in common is a thing for genre-bending, radical left turns and keeping listeners on their tippy toes.', 'https://dekmantelfestival.com/artists/dirtylang')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('DJ Koolt', 'dj koolt', false, 'DJ Koolt has been pivotal to the rise of his native Uruguayan scene since he began spinning in the ’90s. Firmly rooted in Montevideo, he has helped shape the city into one of the most exciting places to hear minimalist dance music. His spiritual home is Phonotheque, the club he co-founded more than a decade ago and where he continues to lay down forward-thinking selections for a devoted following. Acid, breaks and techno form the foundations of his sound, embellished in signature style with spaced-out textures, gritty industrial futurism and flashes of avant-garde electronics. Last seen at Dekmantel Festival ’25, we’re pleased to welcome this vinyl-obsessed legend back to the decks.', 'https://dekmantelfestival.com/artists/dj-koolt-2')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective)
  VALUES ('DJ Nobu', 'dj nobu', false)
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Wata Igarashi', 'wata igarashi', false, 'Wata Igarashi takes to the RADAR stage, bringing his signature strain of crystalline techno into focus. The Dekmantel label affiliate — who also appears for a B2B with DJ Nobu during the festival — carves out spiralling sound worlds built on tunnelling basslines and cascading arpeggiator patterns. Drawing on a deep knowledge of psychedelia and a hardware-heavy studio practice, his mixes favour slow harmonic shifts and carefully layered tonal movement. Under his steady hand, frequencies and intensities are shaped with measured control, easing the dancefloor into a dreamlike state where luminous, cloud-like synths cut through dense rhythmic pressure.', 'https://dekmantelfestival.com/artists/wata-igarashi')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Dj Spanish Fly', 'dj spanish fly', false, 'Legend alert! Dj Spanish Fly (real name: Antonio Kimbrough) is a foundational figure in the Memphis rap scene and one of the architects of its early sound. Starting out in the ’80s as a house DJ and bedroom rapper, he helped shift the city’s club signature from disco toward hip-hop, distributing raw, bass-heavy mixtapes that would go on to define the Memphis aesthetic – which he describes as a “wicked, 808, slow, dope groove.” His hypnotic yet aggressive rhythms and pioneering use of drum machines laid the groundwork for generations of Southern artists and a sound that’s now a global phenomenon. Today, Fly’s legacy continues to resonate as a link between local dance culture and the global evolution of electronic and rap music.', 'https://dekmantelfestival.com/artists/dj-spanish-fly')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('DJ Sprinkles'' Deeperama', 'dj sprinkles'' deeperama', false, 'If you know anything about DJ Sprinkles, it’s that anything is possible and nothing is predictable. A rebellious figure in today’s electronic music landscape, Terre Thaemlitz underscores dance music’s origins – and its enduring potential – as a queer, political and conceptual medium. In the 2000s, DJ Sprinkles hosted her own Deeperama events at Module club in Shibuya, Tokyo, which emphasised deep, attentive listening. Later, these explorative mixes were released as a series of CDs, which became something of a cult phenomenon. At Dekmantel Festival ’26, DJ Sprinkles will revive the Deeperama series with a must-hear morning set.

Please note that this act is part of Dekmantel at Dawn, which is exclusively accessible to weekend ticket holders.', 'https://dekmantelfestival.com/artists/dj-sprinkles-deeperama')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Dopplereffekt', 'dopplereffekt', false, 'Situated at the intersection of electro, techno, and quantum physics, Dopplereffekt function less as performers than as system engineers. Emerging from Detroit in the mid-1990s, the project was founded by Gerald Donald following his work with Drexciya, alongside collaborators such as Rudolf Klorzeiger, To Nhan Le Thi, and Beatrice Ottmann. Over three decades, their output has carried forward Detroit’s sci-fi tradition through sound, exploring automation and human obsolescence via austere rhythms and synthetic voices. To witness them live is to encounter the place where music and science meet – electronica at its most rigorous and conceptual: precision over nostalgia, electro as experiment, and the dancefloor as laboratory.', 'https://dekmantelfestival.com/artists/dopplereffekt')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Doudou MD', 'doudou md', false, 'A familiar force within the Dekmantel universe, Doudou MD returns with the assurance of an artist whose range and intuition continue to deepen. Known for sets that refuse repetition, her sonic language moves fluidly between house, swung techno, UK garage, dubwise pressure, and left-field electronics, always guided by rhythm, groove, and feel rather than formula. Born to a Dutch classical singer and pianist and a Congolese percussionist, her musical lineage is palpable: percussion leads, melodies spiral, and time bends. Working primarily with vinyl, Doudou MD draws from the rich archives of British, American, and German electronic music, layering hypnotic structures with a spiritual charge. With long-standing ties to Utrecht’s SlapFunk and regular appearances with Amsterdam’s VBX, she has firmly established herself as a selector defined by depth, curiosity, and forward momentum.', 'https://dekmantelfestival.com/artists/doudou-md-2')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective)
  VALUES ('Dr. Rubinstein', 'dr. rubinstein', false)
