  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('DVS1', 'dvs1', false, 'What can we say about DVS1 that hasn’t already been said? Zak Khutoretsky embodies the ever-beating, unrelenting heart of techno – whether through his deep, immersive and endlessly expansive DJ sets, his stripped-back yet richly detailed productions on the world’s most respected labels, or through scene-shaping projects such as HUSH and Aslice. A storyteller who has dedicated his life to nurturing underground electronic music and its community while pushing back against commercial pressures, his vision remains as uncompromising today as it was 30 years ago. Needless to say, we can’t imagine Dekmantel Festival without his dark arts.', 'https://dekmantelfestival.com/artists/dvs1')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective)
  VALUES ('Efdemin', 'efdemin', false)
  ON CONFLICT (sort_name) DO UPDATE SET
