  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Polygonia', 'polygonia', false, 'The alter ego of multidisciplinary artist Lindsey Wang, Polygonia seamlessly blends elements of techno, downtempo and ambient. Inspired by the natural world and informed by a deep understanding of music theory and instrumentation, her sound brims with intricate, organic shapes and mystical atmospheres. At Dekmantel 2026, Polygonia appears in an extraordinary double billing: a B2B with fellow Berlin mainstay Efdemin and a solo set on RADAR, showcasing her uniquely sculptural approach to rhythm and atmosphere in full.', 'https://dekmantelfestival.com/artists/polygonia')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
