  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Eris Drew presents Mystery of the Motherbeat', 'eris drew presents mystery of the motherbeat', false, 'Just as there are certain dancefloor sensations that must be felt rather than expressed in words, the Motherbeat should be experienced. Channeled as her life’s work by house music icon and Dekmantel regular Eris Drew, its mystery is translated to a sonic conjuring she describes as follows: “The moment I feel everyone is open I hold the record in front of me with both hands and offer it in a gesture. […] I close my eyes and allow something Mandela-like to form. Through this spiralling gate I send messages of love, healing and even forgiveness.” This year, Eris brings the ritual – and her one-of-a-kind vinyl collection – to our morning gathering in the forest. You are invited.', 'https://dekmantelfestival.com/artists/eris-drew-presents-mystery-of-the-motherbeat')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

