  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('FJAAK Hybrid', 'fjaak hybrid', false, 'The techno boyband par excellence, FJAAK are Felix Wagner and Aaron Röbig. The pair grew up together in Spandau, on the outskirts of the German capital, before gravitating towards the city’s centre – and its techno pulse. Led by a hands-on, hardware-heavy setup, FJAAK draw on Berlin’s lineage while letting UK garage swing and breakbeat pressure seep in, landing somewhere between raw energy and playful excess. At heart, it’s still just two friends having a wicked time geeking out over music, guided by a non-conformist streak and plenty of humour. For Dekmantel, they bring a hybrid live/DJ performance that flexes their analogue muscle: loose, elastic, and driven by the joy of getting lost in the mix.', 'https://dekmantelfestival.com/artists/fjaak-hybrid')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

