  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Fumiya Tanaka', 'fumiya tanaka', false, 'Fumiya Tanaka is a cornerstone of Japanese electronic music and a quietly influential figure in global techno. Active since the early ’90s, his work helped shape a deeper, more minimal approach to dance music, rooted in subtle restraint and long-form progression. As a DJ, Tanaka is known for sets that unfold patiently, balancing hypnotic techno with cosmic house and experimental textures. Beyond the booth, he has played a vital role in nurturing underground culture through his labels, including his current Sundance imprint, bridging scenes between Japan and Europe.', 'https://dekmantelfestival.com/artists/fumiya-tanaka')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Gabrielle Kwarteng', 'gabrielle kwarteng', false, 'Championing the house grooves of New York, where she was born and raised, the now Berlin-based Gabrielle Kwarteng knows like no other how to keep dancers locked in. During her regular radio appearances on NYC’s The Lot, Berlin’s Refuge, or London’s NTS, she showcases her far reaching music taste. Kwarteng weaves together different decades of electronic music with impressive ease: from the freshest techno cuts, to funk and early house, but always honouring the Black roots of dance music. As she has shown during her many previous Dekmantel, Lentekabinet, or Dekmantel Selectors sets, there’s no escaping from the infectious energy when Kwarteng is in charge of the dancefloor.', 'https://dekmantelfestival.com/artists/gabrielle-kwarteng')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
