  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Gyrofield', 'gyrofield', false, 'Very few artists in contemporary drum & bass have experienced a rise as rapid – or as closely watched – as Gyrofield. Born and raised in Hong Kong, Kiana Li has carved out a singular presence through releases that veer from dystopian, industrial-weight pressure to psychedelic, off-grid explorations, resisting fixed genre logic at every turn. A self-described egirl with a soft spot for cats, Gyrofield pairs sharp technical precision with an instinct for narrative world-building, producing tracks that feel as psychologically charged as they are physically forceful. Whether operating at breakneck tempos or dissolving rhythm altogether, her work – both behind the DJ booth and in the studio – is defined by constant mutation. To follow Gyrofield is to accept that she will never settle into one sound, one tempo, or one expectation – only an ever-shifting system, perpetually reconfiguring itself in real time.', 'https://dekmantelfestival.com/artists/gyrofield')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Headache', 'headache', false, 'Headache is the introspective alias of London producer Joe Thornalley, also known as Vegyn. Where Vegyn leans toward crisp beats and experimental pop, Headache opens up a more fragile, dreamlike terrain. Through ambient sketches, submerged, trip-hop-adjacent melodies, and glitchy fragments, the project coalesces around diaristic lyrics written by Francis Hornsby Clark and performed by AI – an uncanny element that electrifies the music, blurring confession with synthetic performance. Released primarily via the PLZ Make It Ruins label, Headache has cultivated a devoted following for its hazy atmosphere and quietly arresting emotional pull.', 'https://dekmantelfestival.com/artists/headache')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective)
  VALUES ('Helena Hauff', 'helena hauff', false)
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective)
  VALUES ('L.F.T.', 'l.f.t.', false)
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Identified Patient', 'identified patient', false, 'Identified Patient, aka Job Veerman, stands as one of the Netherlands’ most vital underground DJs and producers. Renowned for high-voltage sets that crackle and spark, moving lithely between techno, bass, acid, wave, and industrial, his sound carries a dark romanticism, thriving on tension and controlled chaos. A long-standing Dekmantel favourite, Veerman returned to the label in 2025 for the third time with Reset, a future-facing EP that pairs crushing low-end frequencies with razor-sharp precision. Across further releases on Dekmantel and his own Nerve Collect imprint, co-run with Gamma Intel, Identified Patient delivers club music that is bold and unapologetically physical – engineered to unsettle and seduce in equal measure.', 'https://dekmantelfestival.com/artists/identified-patient')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Ikonika', 'ikonika', false, 'Emerging out of the late-2000s dubstep vanguard – one of the few non-male acts visible within the scene at the time – and the UK funky underground, Ikonika cut against bass music’s darker orthodoxies with colour, swing, and emotional depth. With releases on Night Slugs, Planet Mu, and Don’t Be Afraid (DBA), they have long been affiliated with the influential Hyperdub label, which released their debut album Contact, Love, Want, Have (2010) – a pioneering record blending elements of garage, synth-pop, and R&B with bright melodies and retro-futurist textures. Decades on from their breakout, Ikonika shows no signs of slowing down, continuing to put out singular productions and deliver highly dynamic DJ sets that reassemble UK club languages into a powerfully fresh vernacular – mischievous, melodic, and unmistakably London.', 'https://dekmantelfestival.com/artists/ikonika')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Interstellar Funk', 'interstellar funk', false, 'As a member of the Dekmantel family since its earliest days, Interstellar Funk has continuously revealed the many facets of his sonic world. From live performances and adventurous B2B pairings to his legendary Greenhouse closing at Dekmantel Ten, his signature is unmistakable yet always surprising Bridging dark and light, past and future, his sound is driven by razor-sharp drums and coloured by melodic synths. Over the years, he has become an essential figure in Amsterdam’s nightlife. Not only leaving his mark as a DJ and producer, but also through his recent work curating the Dekmantel label, and as one of the founders of local listening bar San Francisco.', 'https://dekmantelfestival.com/artists/interstellar-funk')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Introspekt', 'introspekt', false, 'Leading the charge for the bassweight renaissance, Introspekt shows how much vitality lies in garage and dubstep when it''s approached from a fresh angle. From her early days immersed in raves in LA to the recent highlight of her debut album on the mighty Tempa, Introspekt has come far in a short time and her success is firmly rooted in her reverence for the culture. As a trans artist from America''s West Coast, her quest to reconnect garage with its queer roots ensures her sound is vital and true, and that shows in the knowledge she brings to the party each and every time she steps up.', 'https://dekmantelfestival.com/artists/introspekt')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

