  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Jane Fitz presents Morning Colours', 'jane fitz presents morning colours', false, 'If you’ve ever listened to Jane Fitz’s ‘Colours in the Night’ radio show, you know it’s just as spellbinding as her moments behind the decks – many of which we’ve had the pleasure of experiencing at our festival. The show is a curated amalgamation of sounds the London-based cult DJ cannot play in her techno-oriented sets: from contemporary downtempo and ambient to archival Italo and cosmic disco. Fitz herself describes it as a collision of old and new music, but: “this is not a mix show, nor DJing, just non-club sounds I really love and want to share.” During our new morning program at the Amsterdamse Bos, she will present its first-ever AM episode for a live audience.

Please note that this act is part of Dekmantel at Dawn, which is exclusively accessible to weekend ticket holders.', 'https://dekmantelfestival.com/artists/jane-fitz-presents-morning-colours')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Jasmín', 'jasmín', false, 'If you set foot on any proper dance floor in the past year, there’s a good chance you moved to Jasmín’s ‘Bite the Hand’. A favourite among our favourite DJs, the brilliant club track catapulted the DJ – a long-time Dekmantel favourite who came up as a regular at De School – to new heights, and made her the first Dutch artist to appear on Hessle Audio. Driving, gloomy, percussive, brainy, intricate, roaring – it’s the perfect example of what Jasmín does best in both her productions and sets: elevating dance music while weaving together (sub)genres and toying with crowd expectations. This summer, she’s stepping back into the RADAR arena.', 'https://dekmantelfestival.com/artists/jasmín')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

