  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Jeff Mills debuts STARGATE', 'jeff mills debuts stargate', false, 'Jeff Mills kicking off your festival day with a morning premiere – yes, that’s actually happening! This summer, The Wizard returns to the Amsterdam forest to debut STARGATE: a brand new project, shrouded in mystery (for now). What can we say? One of the greatest artists of our time, who last closed our main stage with a mind-expanding set in ’24, will now play under the beloved willows of our Selectors stage for the very first time. Welcome to Dekmantel at Dawn.

Please note that this act is part of Dekmantel at Dawn, which is exclusively accessible to weekend ticket holders.', 'https://dekmantelfestival.com/artists/jeff-mills-debuts-stargate')
  ON CONFLICT (sort_name) DO UPDATE SET
