    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Josey Rebelle', 'josey rebelle', false, 'Raised within Caribbean sound system culture, Josey Rebelle started DJing at 13, teaching herself to mix with records from her brother’s vinyl collection. Years of obsessive practice took her from bedroom sessions to the booth at London’s legendary Plastic People, and later to a decade-long run on Rinse FM. Today, she is recognised as one of the world’s most vital selectors. Rebelle’s sets are defined by motion. House mutates into jungle, dub collides with techno, tempos shift in an instant — but the energy never dips. Moving with total freedom across genres, she threads every turn with precision, pressure, and control. Whether in a darkened club or out in the open air, Josey Rebelle knows exactly how to lock into a dancefloor and lead it somewhere unexpected. On Thursday night at Melkweg for Dekmantel ’26, she takes dancers deeper into the afterhours.', 'https://dekmantelfestival.com/artists/josey-rebelle')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Juan Atkins', 'juan atkins', false, 'Few figures loom as large in the history of electronic music as Juan Atkins. Widely regarded as one of the original architects of Detroit techno, the Metroplex founder helped shape a sound that would travel from the Motor City to dancefloors around the world. Through pioneering projects such as Cybotron and Model 500, Atkins fused electro, funk and futurist machine rhythms into a blueprint for modern techno. Decades on, his influence remains immeasurable. As a DJ, he moves fluidly between past and future, threading together the genre’s roots with its ever-evolving possibilities — a reminder that techno’s original vision of science fiction, soul and circuitry still resonates today. In addition to DJing on the RADAR stage, Atkins performs live as Infiniti on Thursday evening, marking 30 years since the release of his debut album under the alias.', 'https://dekmantelfestival.com/artists/juan-atkins')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Juan Atkins presents Infiniti', 'juan atkins presents infiniti', false, 'Under the moniker Infiniti, Juan Atkins – widely cited as the original pioneer of Detroit techno – combines raw tactility with puristic elegance, shaping a biomorphic atmosphere of industrial soul. At just 15, Atkins purchased his first synthesiser, setting off a trajectory that would redefine electronic music. Alongside solo work as Model 500, and as part of Belleville Three, Cybotron, and Borderland, his influence remains foundational. Conceived as a vessel for ideas beyond fixed authorship or era, Infiniti channels Atkins’ most abstract impulses into lean, forward-driving machine funk. Across two full-length albums – The Infiniti Collection (1996) and Skynet (1998), both released on Tresor – the project articulated a future-facing vision of techno as both science and spirit. Reviving Infiniti for Dekmantel 2026, he brings history into the present – not as nostalgia, but as a living system.', 'https://dekmantelfestival.com/artists/juan-atkins-presents-infiniti')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Jyoty', 'jyoty', false, 'If anyone came, saw, and conquered the RADAR stage at Dekmantel Festival’s 10th edition, it’s Jyoty (just head to YouTube for the proof). Born in Amsterdam but rising to prominence via London, the ascent of this super-skilled selector – from online radio and local clubs to sold-out world tours – has been a joy to witness. It surely has something to do with the pure joy Jyoty Singh exudes behind the decks, where she jumbles global elements of bass, breaks, hip-hop, funk, grime, dancehall and more. This summer, the newly crowned star steps out of the streaming arena and onto our big festival stage.', 'https://dekmantelfestival.com/artists/jyoty')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Katatonic Silentio', 'katatonic silentio', false, 'Behind the Katatonic Silentio project is Mariachiara Troianiello, an Italian sound artist and researcher working across electronic music, performance and sound studies. Both as a live performer/producer and independent researcher, her practice moves between disciplines and approaches to sonic production. Active as a DJ for two decades, her sets range from abstract musique concrète through spoken word, ambient and dub, to more club-oriented forms including techno, industrial and DnB. With Katatonic Silentio – coming to Dekmantel Festival for the first time – Troianiello zooms in on the severe zone between techno, industrial, noise and sound art, prioritising texture, tension and negative space over club-functional rhythms.', 'https://dekmantelfestival.com/artists/katatonic-silentio')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Khadija Al Hanafi Hybrid', 'khadija al hanafi hybrid', false, 'Tunisian producer Khadija Al Hanafi operates at the meeting point of high-speed rhythm and hazy atmosphere. Her tracks weave Chicago footwork and juke tempos with Jersey club, rap, and glitchy digital textures – pairing frenetic drum programming with woozy melodies, warped samples, and a distinctly soft-psychedelic touch. Albums !OK! and Slime Patrol 2 were given top ratings by Pitchfork, while her residency on NTS Radio offers a glimpse into a love of experimental dance music, lo-fi soul, and rap. For this hybrid set – part live production, part razor-sharp DJing – expect fast rhythms, blurred edges, and a dancefloor that feels both intimate and explosive.', 'https://dekmantelfestival.com/artists/khadija-al-hanafi-hybrid')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Kode9 presents Hyperdub', 'kode9 presents hyperdub', false, 'Emerging from the 1990s underground – pirate radio, smoke-thick basements, and renegade academia – Kode9 has become one of the UK’s most singular forces. Author of the formative book Sonic Warfare (2010), which analyses the “politics of frequency,” he has, as producer, theorist, and founder of Hyperdub, shaped the trajectory of contemporary bass music, championing innovations that bridge jungle, footwork, UK garage, gqom, dubstep, and sounds yet to be named. Hyperdub’s catalogue – launching Burial and nurturing artists like Jessy Lanza, DJ Rashad, and Laurel Halo – remains a lodestar for the experimental and the club-ready alike. For Dekmantel 2026, Kode9 delivers a Hyperdub takeover that showcases the label’s 20+ year legacy – from its most iconic records to deep-cut gems – channelling a restless, future-facing energy into a set primed to warp space and time.', 'https://dekmantelfestival.com/artists/kode9-presents-hyperdub')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Konduku', 'konduku', false, 'Konduku (real name Ruben Üvez) is living proof of techno’s cerebral and expansive potential. A skilled DJ who has steadily climbed to the top, his sets – immersive, percussive and often polyrhythmic – stand out for their ability to blend and layer sounds that conjure otherworldly hypnotism and radical genre hybrids. As an equally accomplished producer, he is most commonly associated with the wondrous world of Nous’klaer, as well as DJ Nobu’s Bitta imprint and Dozzy and Neel’s Spazio Disponibile. Following last year’s standout RADAR set – which you can still enjoy on YouTube – we’re thrilled to welcome him back.', 'https://dekmantelfestival.com/artists/konduku')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

