  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Lea Occhi', 'lea occhi', false, 'For Lea Occhi, music has always been a place to land. Her early memories are scored by jazz, soul, and chansons; later, as a teenager, that quiet devotion tipped into a fascination with electronica. The French DJ, now residing in Amsterdam, works with tension and release as raw material. Rooted in techno yet open in shape, her sets roll through heady, hypnotic rhythms, earthy textures, and pockets of air, guided by a finely tuned sense of timing and atmosphere. A digger by instinct, Lea has a particular talent for churning up unique blends of micro-house, deep, and ambient tracks. In 2017, she co-founded Spectrum Waves, a Paris-based queer collective centred on safer spaces, care, and community – values that continue to pulse through her sound.', 'https://dekmantelfestival.com/artists/lea-occhi')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('livwutang', 'livwutang', false, 'Livwutang (Seattle-raised, NYC-based) came up through DIY raves and pirate radio and is now a regular at cult clubs and festivals across the globe. Her sound moves freely between hypnotic dub, Central and West African rhythms and the history of Black American music. All of this comes through in her widescreen sets, her curation of the Eto Ano label and her hosting of its show on The Lot Radio. What makes livwutang stand out among her peers is the confidence of her selections and her ability to shift through moods: from the serene to the deep, the energetic to the melodic – subtly shifting from dubbed-out depths to buoyant club rhythms via tribal techno. There’s an ever-present spirituality that adds an extra layer of intrigue to her sound, which you simply have to experience in the flesh.', 'https://dekmantelfestival.com/artists/livwutang')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Loradeniz', 'loradeniz', false, 'DJ, pianist, producer, vocalist, and composer, Loradeniz is a kaleidoscopic tour-de-force. The multidisciplinary project conceived by Istanbul-born, Amsterdam-based artist Deniz Omeroglu has quietly grown into a cult name, particularly known for hypnotic and deeply sensitive, voice-led records released on labels such as Music From Memory, Nous’klaer Audio, and Artificial Dance. Drawing on a wide-ranging musical background rooted in classical training and experimental sound design, she channels this breadth into immersive mixes that drift between deep house, bass, psychedelic techno, trance, ambient, and acid. With Loradeniz, the dancefloor deepens into a shifting, oceanic terrain – contours merging, dissolving, and reforming, shaped as much by atmosphere as by rhythm.', 'https://dekmantelfestival.com/artists/loradeniz')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

