  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Makam presents The Archive', 'makam presents the archive', false, 'House music as a launching pad for deep experimentation – that’s how Guy Blanken approaches his Makam moniker. Rooted in warm, rolling house but stretching into hypnotic, psychedelic and percussive territory, Makam is Blanken’s most exploratory outlet. One of the best DJs the Dutch scene has to offer – protect him at all costs – he is equally loved for his techno-oriented work as Talismann. In 2026, Makam returns to Dekmantel Records with the brilliant ‘Tarp’ EP. This summer, the longtime Dekmantel resident is back in the Amsterdam forest with a special show that unearths his boundless archive.', 'https://dekmantelfestival.com/artists/makam-presents-the-archive-live')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Mala', 'mala', false, 'Few can lay claim to helping invent a new genre in the 21st century, yet Mala most definitely can. In the early 2000s, as a member of the groundbreaking DMZ collective, his mystical, sub-heavy sound captured the imagination of a generation of ravers, giving rise to the grimy, layered textures of dubstep. As dubstep spread across the globe, Mala’s focus turned toward the deeper roots of soundsystem culture, exploring connections between bass traditions and new dance music forms. Guided by principles of sustainability and collaboration, his work — as a producer, DJ and label head — continues to influence contemporary sounds and styles, pushing them into new territory. At Dekmantel ’26 Mala appears twice (dub fans rejoice!): for a solo set on RADAR and a B2B with fellow Deep Medi affiliate Sir Spyro.', 'https://dekmantelfestival.com/artists/mala')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective)
  VALUES ('Sir Spyro', 'sir spyro', false)
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Marcel Dettmann', 'marcel dettmann', false, 'Marcel Dettmann’s name is synonymous with Berlin’s techno lineage, yet for Dekmantel 2026 he opens a different door. His house sets are not nostalgic detours but precision-built journeys: stripped-back, rhythm-driven, and quietly subversive. Drawing on early ’90s club energy, warped grooves, and tracks that sit just off-centre, Dettmann threads momentum with restraint, letting swing, pressure, and texture do the heavy lifting. A longtime resident of Berghain and a central figure in shaping its sound, he approaches the dancefloor as a curator as much as a DJ. Across decades of releases, label projects, and work spanning contemporary art, film, and performance, Dettmann has continually expanded what dance music can be – making this house set less a stylistic shift than a rare glimpse into the full breadth of his musical thinking.', 'https://dekmantelfestival.com/artists/marcel-dettmann')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Mia Koden', 'mia koden', false, 'Mia Koden is all about the low end. Drawing on her South Sudanese heritage, years spent in Ghana and Nigeria, and the influence of London’s sound system culture, she balances tradition with rhythmic invention – reshaping heavy sounds into intense, playful, and irresistible new forms. She often laces her own tracks into her sets, channeling a raw, percussive approach that cuts through dubstep, 2-step, breaks, and techno. Following multiple appearances at the festival, it’s safe to say she is firmly part of the Dekmantel family: a vital, uncompromising selector with bass-and-percussion-driven instincts and a taste for the unexpected.', 'https://dekmantelfestival.com/artists/mia-koden')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Mike Parker', 'mike parker', false, 'Mike Parker is, as you might expect, a perfectionist. His take on techno is meticulous, his grooves as hypnotic as any. Over the course of three decades, the American DJ – who started out playing warehouse parties in the mid-1990s – has honed his vision with ever-increasing precision. As a producer, he packs remarkable amounts of detail into his tracks, elevating them far beyond purely functional material. That approach has seen his music released on labels such as Semantica, Tresor, Spazio Disponibile and Field Records, alongside his own imprint, Geophone. It’s been almost 10 years since this club veteran last joined us in the festival forest, and we’re thrilled to welcome him back for a live set.', 'https://dekmantelfestival.com/artists/mike-parker-live')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Molina', 'molina', false, 'Rebecca Molina is a Copenhagen-based artist working at the intersection of mood-building songwriting, sample-based electronics and hand-played instrumentation. Her fuzzed-out compositions are marked by restraint and precision, drawing on minimal pop structures, dubby spatial logic and a close, unguarded vocal presence. Released through the Escho imprint, Molina’s sounds move with quiet intent between the listening space and the club, focussing on tone, pacing and physical detail rather than grand gestures. This summer, she will make her Dekmantel Festival debut with a Thursday concert.', 'https://dekmantelfestival.com/artists/molina')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Nala Brown', 'nala brown', false, 'It’s often easy to tell if a DJ loves dancing by the way they play and the energy they bring to a room. Jacqueline Monteiro, who goes by the moniker Nala Brown, is one of those DJs who makes it hard to stay still whenever she steps into the booth. Her sets are an eclectic blend of tracks by Detroit legends, New York’s new generation of club music producers, edits of her favourite contemporary pop and R&B stars, and a generous dose of high‑energy percussion. While often tapping into her Cape Verdean roots, Nala Brown was born and raised in Rotterdam, where she has organised various parties and hosted community talks with the all-femme AMPFEMININE nightlife collective.', 'https://dekmantelfestival.com/artists/nala-brown')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Nazar Hybrid', 'nazar hybrid', false, 'Operating at the brutal edge of electronic sound, Nazar forges what he has termed ''rough kuduro'': a mutation of Angolan dance rhythms shaped by distortion and noise. Raised between Central Africa and Europe – and now based in Amsterdam – Nazar channels personal and political histories into sonic material, treating bass as pressure and rhythm as rupture. Returning to music following a long illness, his recent work has grown increasingly cinematic and severe, collapsing dancefloor structures into tense, militarised forms where percussion lands like impact and silence carries threat. For Dekmantel 2026, he delivers a hybrid set that sits between DJing and composition; volatile and exhilaratingly formidable.', 'https://dekmantelfestival.com/artists/nazar-hybrid')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Neska', 'neska', false, 'Peppered with twists, turns, and elegant surprises, Neska builds mixes through careful excavation. Basque-born and shaped by backgrounds in classical, jazz, and punk, her DJing folds disparate lineages into a cohesive logic – where rhythm bends, forms dissolve, and expectations are quietly subverted. Now based in Amsterdam via Barcelona, she has appeared across major Spanish festivals and Dutch clubs, carving out a reputation for sets that are psychedelic and grounded in physical presence, drawing from dub and experimental pulse. Beyond the booth, she curates fauna & flora, a multidisciplinary platform connecting electronic music with site-responsive art installations, and hosts Neskafe, a forward-looking residency on Echobox Radio. Attentive to detail, pacing, and atmosphere, Neska treats the dancefloor as a space for curiosity and sustained attention.', 'https://dekmantelfestival.com/artists/neska')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('NEW YORK', 'new york', false, 'Your new favourite band: NEW YORK. The London-based duo – Coumba Samba and Gretchen Lawrence – quickly gained cult attention with their debut album No Sleep Till NY, hailed as one of 2022’s standout discoveries for its icy electro surfaces, body-shaking reggaeton rhythms, and brazenly filthy lyricism. Hot on the heels of their 2025 record Push, a release that pushes their dark, bracing, and deliciously uncanny sound into deeper waters, NEW YORK continue to blur the lines between pop immediacy and experimental intent. Too smart and elusive to sit comfortably inside ''indie revivalist'' narratives, NEW YORK operate on their own terms – where pop, club pressure, and visual art intuition intersect.', 'https://dekmantelfestival.com/artists/new-york')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Nicolas Lutz', 'nicolas lutz', false, 'Nicolas Lutz, originally from Montevideo, Uruguay, operates firmly at the outer limits of dancefloor culture. A cult selector with an instinct for the margins, he’s known for testing the unfamiliar in real time – unearthing strange, overlooked records and letting them slowly reveal their power. His sets slip through shadowy zones and sudden left turns, guided by feel rather than fashion. Precision without rigidity, curiosity without compromise, Lutz brings the same philosophy to his My Own Jupiter label, where patience, depth and discovery remain the guiding principles. As a DJ, he favours off-grid house and techno, broken electro, and cosmic oddities – expect extended arcs and carefully calibrated tension; his authority lies not in spectacle, but in unfaltering intuition.', 'https://dekmantelfestival.com/artists/nicolas-lutz')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Nicolini', 'nicolini', false, 'Somewhere in the DIY territory between dubby wave, mutant dancehall, low-slung steppers and 180-bpm experiments, you’ll find Nicolini. A project by Nic Mauskovic – also known for The Mauskovic Dance Band and as one half of Devon Rexi – Nicolini is the type of act you’d expect to soundtrack the disco in a David Lynch epoch, were it filmed in the 2020s. This summer, you’re invited to step into a live version of his sonic fever dreams: pleasantly hazy with no intent of clarifying themselves.', 'https://dekmantelfestival.com/artists/nicolini-live')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Nídia', 'nídia', false, 'Raised in Vale da Amoreira, Portugal, Nídia came of age surrounded by the Lusophone African community’s rhythmic traditions and DIY street sound systems. Drawing in particular on kuduro – the high-energy Angolan dance music driven by fast tempos and hard percussion – she pushes decisively toward new sonic futures: fractured, forceful, and fiercely alive. As a key artist within Príncipe Discos, the Lisbon-based label and collective central to Afro-Portuguese club culture, Nídia has helped redefine how grassroots scenes reverberate internationally. Both her productions and DJ sets are agile and uncompromising, built on syncopated beats, sudden drops, and relentless forward motion – rooted in the hyper-local yet primed for dancefloors worldwide.', 'https://dekmantelfestival.com/artists/nídia')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('NIKS', 'niks', false, 'NTS, Rinse FM, and BBC Radio regular NIKS has left a significant mark on current club culture, extending far beyond her work as a DJ and producer. She co-founded the Black Artist Database, a crowd-sourced resource of Black-owned labels, artists, and producers designed to amplify and uplift talent – now expanded into its own label and event series. Her house-focused sets draw from 90s breaks and groovy techno, and in true Londoner fashion: she always leaves space for warm bass and dub influences.', 'https://dekmantelfestival.com/artists/niks-2')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
