  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Octo Octa (DnB set)', 'octo octa (dnb set)', false, 'As a teenager, drum and bass was Octo Octa’s first love. Long before becoming known for her euphoric, emotionally rich strain of house and techno, the T4T LUV NRG co-founder and turntablist extraordinaire was immersed in the warp and propulsion of DnB. In this deeply personal set, she returns to the music that first drew her to DJing — digging into formative records, mix CD staples and long-held favourites. Revisiting these sounds with decades of experience behind the decks, Octo Octa channels bass pressure and breaks with her signature joy and infectious intensity.', 'https://dekmantelfestival.com/artists/octo-octa-dnd-set')
  ON CONFLICT (sort_name) DO UPDATE SET
