  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Rene Wise', 'rene wise', false, 'Moving Pressure label head Rene Wise is drawn to polyrhythms. With an astute ability to layer tracks over multiple decks, he draws on his background in percussion, taking cues from his Iranian father, a professional drummer. Channelling this musical heritage through his sparse-but-driving techno, Wise''s ''quality over quantity'' mindset has seen him become a fixture on respected labels like Mote Evolver and BluePrint, collaborating with many industry luminaries. As a DJ, his pure and passionate approach has earned him spots at revered venues like Berghain and Fabric, along with a residency at the esteemed Dutch underground Eerste Communie parties. After a mind-melting set in our UFO during Dekmantel Ten, Rene Wise returns to Amsterdamse Bos.', 'https://dekmantelfestival.com/artists/rene-wise')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective)
  VALUES ('RHR', 'rhr', false)
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Skrillex', 'skrillex', false, 'Sonny John Moore – better known as Skrillex – has built a career few can rival: MTV’s Electronic Dance Music Artist of the Year and the distinction of being the most awarded electronic artist in Grammy history. Rising to prominence during the early-2010s explosion of dubstep, he helped push the sound into the global mainstream before years of restless reinvention across pop, rap, and club music. More recently, he has turned his attention back toward the underground, collaborating with boundary-pushing artists such as RHR and Slikback while exploring rawer textures and bass mutations – all without losing his signature bombastic style. He makes his Dekmantel debut in ’26 – and it’s a double helping; don’t miss a special B2B with RHR happening the same day.', 'https://dekmantelfestival.com/artists/skrillex')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Ricardo Villalobos', 'ricardo villalobos', false, 'It’s been exactly eight years since Ricardo Villalobos last set foot in a Dekmantel booth. This summer, the Chilean-German artist returns, teleporting his elusive aura back to the Amsterdamse Bos. For those who’ve experienced Villalobos in the flesh, little introduction is needed. For those still too fresh to have a clue: come see – Hear! Inhale! Feel! – the minimal master at work. Especially at a time when club tempos and transitions feel more volatile than ever, there’s something uniquely powerful about Villalobos’s ability to work with house and techno at a microscopic level: the endless builds and blends, and the poetic, irresistible sense of groove that’s simply impossible to capture in words. Like a hypnotic, boundless jazz improvisation, his sets are minutely sculpted – slowed, sped up, shaved – and gently steered towards bliss. Villalobos doesn’t just play records; he reinvents time. We’re proud to welcome him back.', 'https://dekmantelfestival.com/artists/ricardo-villalobos')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective)
  VALUES ('Ron Trent presents LA MARR', 'ron trent presents la marr', true)
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective)
  VALUES ('Pablo Color', 'pablo color', false)
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Rozaly', 'rozaly', false, 'Rozaly is a Curaçao-born sound artist, researcher and DJ, who came up through Amsterdam’s electronic scene. Blending Caribbean sounds into a contemporary club context, he challenges traditional ideas surrounding his roots while expanding and toying with cultural narratives. Having previously joined us for Dekmantel Festival, Selectors and Lentekabinet, we likely don’t have to tell you what a DJ-set by this whiz entails: blazing percussion, life-size chants and global rhythms – underscored by bass, bass and more bass. If you’re looking for a party, Rozaly is (always) the way to go.', 'https://dekmantelfestival.com/artists/rozaly')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, source_url)
  VALUES ('Ryan Elliott', 'ryan elliott', false, 'https://dekmantelfestival.com/artists/ryan-elliot')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Sampha DJ set', 'sampha dj set', false, 'When you think of Sampha, the genres that immediately come to mind are likely neo-soul, -R&B, and (alternative) pop. However, the British artist’s identity is deeply shaped by club culture, in particular that of the South London scene he emerged from. Of course, there are his famed collaborations with heavy-hitters like Floating Points, SBTRKT, and Jamie xx – instantly dissolving the boundaries between (what is considered) club and non-club music – but his own, next-level production techniques and dance-adjacent song structures also point back to a firm electronic foundation. This summer, Sampha joins Dekmantel At Dawn for a DJ set – and that’s a rare treat.

Please note that this act is part of Dekmantel at Dawn, which is exclusively accessible to weekend ticket holders.', 'https://dekmantelfestival.com/artists/sampha-dj-set')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Sandrien', 'sandrien', false, 'Thanks to former residencies at some of Amsterdam’s most celebrated (but now-closed) clubs, her role as co-founder of Is Burning, and a renowned record collection, Sandrien has become a local hero. With more than twenty years in the game, her versatile take on techno has carried her far beyond the city: from Japan to Tbilisi to far beyond. Deep yet driving, blending classics with futuristic sounds, her head-spinning selections have earned her the title of a DJ’s favourite DJ. Remarkably, she brings the same mastery, and yet another stash of hidden gems, to her house music sets.', 'https://dekmantelfestival.com/artists/sandrien')
