  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Sepehr presents Leash', 'sepehr presents leash', false, 'You’ve never encountered an artist quite like Sepehr. Tuned into the Middle Eastern underground and based in Berlin, the Iranian-American live act, DJ, and sonic maverick rejects convention and shatters essentialism at every turn. As the founder of Shaytoon Records, he champions diaspora sounds that resist tokenism, encouraging artists to embrace contradiction, risk, and range. His output carries a pariah energy, reshaping dancefloor forms into potent hybrids of acid, dub, techno, electro, EBM, and beyond.


Now, he returns after last year’s Radar live show with a debut live band performance built around a forthcoming Dekmantel album project. This new chapter unfolds as a feverish and romantic sonic reckoning with time. Under the moniker Leash, Sepehr traverses the space where demonic left-field pop meets the worn, grungy residue of past love. Music that restrains you, embraces you, but never fully arrives.', 'https://dekmantelfestival.com/artists/sepehr')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Shed presents Rave Echoes', 'shed presents rave echoes', false, 'A techno true believer, René Pawlowitz has spent more than two decades carving out a fiercely independent strain of house and techno. Working across a web of aliases – EQD, Wax, Head High, WK7 – and most famously as Shed, Pawlowitz treats genre not as a rulebook but as raw material. His sound is dense and analogue-leaning: murky basslines, corroded drum machines, and a restless push-and-pull between funk and austerity. Tracks often feel stripped to the bone yet overloaded with pressure, drawing on early Detroit techno, warehouse house, and Berlin’s harder, dirtier club traditions. For the 2026 edition of the festival, Shed presents Rave Echoes – a live rendition of his upcoming album on the Dekmantel label, carrying the reverberations of yesterday’s dancefloors into the future.', 'https://dekmantelfestival.com/artists/shed-presents-rave-echoes-live')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('SHERELLE', 'sherelle', false, 'In case you missed it, ’25 was the year that SHERELLE (yes, all caps) released her debut record, WITH A VENGEANCE (also all caps). Much like the London artist’s DJ sets – who remembers that iconic closing at The Nest in ’22 or the B2B session with RP Boo in ’24 – her album races through high‑speed dance genres, from DnB, jungle and footwork to acid, techno and hardcore. Add in her meticulously dosed sample chops, vocal percussion and revved-up breaks, and the result is a frenetic, over-the-top joyride (velocity 160+ BPM, emergency brakes non-existent) that you dared yourself to get on – and now can’t get off. All you can do is take a deep breath and embrace the system-shaking thrill.', 'https://dekmantelfestival.com/artists/sherelle')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective)
  VALUES ('Shy FX', 'shy fx', false)
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective)
  VALUES ('Tasha', 'tasha', false)
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Skin On Skin', 'skin on skin', false, 'Big emotions, cheeky edits, and grooves that refuse to behave: this is Skin On Skin in full effect. The South Sudanese-Australian DJ slams together techno, house, and UK drill-inflected hip-hop, crafting a high-impact medley that’s as playful as it is propulsive. His sets thrive on contrast – sudden switches, sticky hooks, and jammy basslines that flirt with chaos. Rising from Brisbane to international stages, he has released on labels including Stay On Sight Recordings, most notably Home Is True – a mixtape of new and old songs that captures his restless, diaristic approach to club music. Known for earworm tracks like “Burn Dem Bridges” – all bruised vocals and swaggering low-end – alongside electric back-to-backs with Skillrex, close collaborator Mall Grab, and others, Skin On Skin turns reckless joy into a finely tuned dancefloor weapon.', 'https://dekmantelfestival.com/artists/skin-on-skin')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('SnPLO', 'snplo', false, 'Artist Profiles - Dekmantel Festival NEWSnPLO is the collaborative project of Canadian artists SnP 500 and Berlin-based producer PLO Man, operating at the crossroads of dubby techno, loop-based experimentation and process-driven club music. Rooted in hardware workflows and a shared fascination with repetition and gradual mutation, SnPLO’s releases distil techno to its most transcendental elements: deep, dense, exploratory and expansive. For Dekmantel Festival 2026, they bring this approach to the upstairs room of Paradiso, where STOOR is hosting its acclaimed live-improv session. Expect loops pushed beyond their limits, and techno emerging in the moment.', 'https://dekmantelfestival.com/artists/snplo-live')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Space Afrika', 'space afrika', false, 'Space Afrika are the Manchester-based duo Joshua Inyang and Joshua Reid, whose spacious productions draw from ambient, dub, trip-hop and Detroit techno. Shaped by the industrial landscapes of Northwest England and notions of travel, their drone-driven work reflects on movement, decay and emotional release, channeled through sound, visuals and performance. After the intimate debut ‘Somewhere Decent To Live’ (2018) and the mixtape ‘hybtwibt?’ (2020), Space Afrika released ‘Honest Labour’ in 2021 – a statement on UK energy, love and loss. The album earned RA’s Album of the Year and Bandcamp’s Best Ambient Album, establishing the duo as one of the most distinctive acts in electronic music right now. On Wednesday, July 29, Space Afrika will officially open our 12th festival edition with a special concert at Amsterdam’s oldest building, Oude Kerk.', 'https://dekmantelfestival.com/artists/space-afrika')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Speedy J', 'speedy j', false, 'Jochem George Paap is a foundational force in Dutch techno and far beyond. Active since the early ’90s, seminal Speedy J albums like Ginger and G‑Spot established him as one of Europe’s pioneering techno producers. While his work has always remained rooted in the robust Rotterdam sound, over the years he has also toyed with the more abstract – constantly exploring new creative terrain and adjacent genres such as ambient and industrial. Speedy J is also the founder of STOOR, an improv-focussed electronic lab and label dedicated to musical, visual, and technological experimentation, and home to his collaborations with artists like Surgeon and Steve Rachmad.', 'https://dekmantelfestival.com/artists/speedy-j')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Steffi', 'steffi', false, 'Decades into her career, Steffi remains as curious and quietly unpredictable as ever. She has been DJing almost continuously since the mid-1990s – first in her hometown of Eindhoven, then Amsterdam, and from 2007 onward in Berlin, where she became a Panorama Bar resident. More recently, in 2020, she relocated with longtime collaborator Virginia to the idyllic Portuguese countryside, a retreat that has seemingly only sharpened her club-forward sensibility. Her recent output, including the much-lauded album Patterns Of Vibration, leans into moments of collective euphoria and dancefloor debauchery. As a DJ, Steffi channels these qualities through groove-led sets that move fluidly between house, techno, and electro-rooted forms, drawing on electronic history while remaining firmly present tense.', 'https://dekmantelfestival.com/artists/steffi')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

