  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('T.NO', 't.no', false, 'Valentino Shakison, better known as T.NO, is one of the freshest producers to emerge from Amsterdam right now. Specialising in speedy, physical club workouts, he blends his Surinamese roots with global dance influences such as gqom, grime, kuduro, bubbling, kawina, and funk carioca. The key ingredients? Rhythm, energy and dynamic flow, channelled through raw percussion and deep bass. Influential labels such as TraTraTrax have already picked up T.NO’s productions, and 2026 promises the release of his debut full-length record – as well as his Dekmantel debut.', 'https://dekmantelfestival.com/artists/t-no')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('The Black Dog', 'the black dog', false, 'The Black Dog are practically synonymous with intelligent dance music, or IDM – the strain of thoughtful electronica they helped bring into being in the early 1990s. Emerging from Sheffield, England, the group’s influential releases on Warp Records – including Bytes (1993) and Spanners (1995) – fused textured rhythms, atmospheric density, and experimental structure into a new electronic vocabulary that, more than thirty years on, continues to serve as a blueprint for producers worldwide. In recent years, The Black Dog have continued to push steadily forward, exploring ambient, techno, and conceptual terrain through albums such as Music for Real Airports (2010) and Other, Like Me (2024), extending practice while retaining a sharply political and textural edge. Following the loss of founding member Ken Downie in December 2025, their live performance at Dekmantel 2026 is sure to honour his enduring legacy: a restless spirit and a lifelong dedication to expanding music''s possibilities.', 'https://dekmantelfestival.com/artists/the-black-dog-live')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

