  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('trickpony', 'trickpony', false, 'Last year, we hosted the unforgettable live debut of Dekmantel regular Katie Campbell – better known as Roza Terenzi. This year, the producer returns alongside fellow Aussie producer Michael Gunson and Helsinki vocalist/producer/designer Maria Korkeila. Together, the three make up Trickpony: a self-described “unconventional prototype band” that creates sensual cyber jams with one nostalgic foot in the past and one dreamy foot in the future. Think trip-hop atmospherics, candle-lit pop, downtempo rollers and spine-tingling, hallucinatory textures. Just weeks ago, Trickpony released their divine debut EP, ‘24/7 Heaven’. Now, the trio makes its Dekmantel Festival debut.', 'https://dekmantelfestival.com/artists/trickpony-live')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

