    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective)
  VALUES ('Saul Williams', 'saul williams', false)
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('upsammy', 'upsammy', false, 'Spatial, intricate, crystalline, transient – there are many beautiful words to describe the upsammy universe. As a producer and multidisciplinary artist, Thessa Torsing subtly shapes explorative sound worlds in which the digital and organic collide. In 2020, following her ‘Wild Chamber’ breakout on Nous’klaer Audio, the artist’s dreamlike debut album ‘Zoom’ was released on our own imprint. Recently, the Dutch artist returned to Dekmantel Records with the EP ‘Open Catalyst’, which reinforces the clubby side of her special sound world: gleaming, sprightly DnB and high-definition techno in the faster zones, always anchored by a restorative centre. At this point, we cannot imagine Dekmantel Festival without upsammy present to tickle our brain cells.', 'https://dekmantelfestival.com/artists/upsammy-2')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Verraco', 'verraco', false, 'With his monumental closing sets at The Nest (Dekmantel ’25 and Selectors ’25) still echoing in our minds, Verraco returns to the line-up in 2026 – this time taking over yet another stage. The club moniker of JP López, a DJ and producer from Medellín, Colombia, known for his distinct blend of techno, Latin-influenced tribal rhythms, hyper-electronica, IDM, and dembow-bass technology. As co-founder of the celebrated TraTraTrax label, Verraco plays a vital role in amplifying Latinx voices across contemporary dance music. His Escándaloo EP (2023) on VOAM and Breathe… Godspeed (2024) on Timedance remain among our favourite releases of recent years, and his ongoing trajectory only sharpens the sense that his appearance at Dekmantel ’26 will be something special.', 'https://dekmantelfestival.com/artists/verraco-2')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Woody92', 'woody92', false, 'A multi-disciplinary artist at heart, Woody92 plays by his own creative rules. Both clubbers and critics have come to adore the way this Dutch DJ weaves together psychoactive strains of leftfield electronics, hypnotic techno and radiant minimalism – resulting in a time-suspending sound that’s hard and unrelenting, yet shimmers with musical intelligence and oddball originality. Since ’21, Woody92 also runs Omen Wapta, the label where his zeal for reinterpreting electronic music comes together with experimental art and design. It’s safe to say this talent is becoming a pillar of the Netherland’s electronic landscape, with a heartfelt vision that travels far beyond.', 'https://dekmantelfestival.com/artists/woody92')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

